#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int N=1003,mod=1004535809;
int n;
ll f[N],mi[N*N],fac[N],g[N];
ll quick_mi(ll a,ll b){
    ll ans=1,base=a;
    while(b){
        if(b&1)
            ans*=base,ans%=mod;
        b>>=1,base*=base,base%=mod;
    }
    return ans;
}
ll C(int a,int b){
    return fac[a]*g[a-b]%mod*g[b]%mod;
}
int main(){
    scanf("%d",&n);
    mi[0]=1;
    for(int i=1;i<=n*(n-1)/2;i++)
        mi[i]=mi[i-1]*2%mod;
    fac[0]=g[0]=1;
    for(int i=1;i<=n;i++)
        fac[i]=fac[i-1]*i%mod,g[i]=quick_mi(fac[i],mod-2);
    f[1]=1;
    for(int i=2;i<=n;i++){
        f[i]=mi[i*(i-1)/2];
        for(int j=1;j<i;j++)
            f[i]=(mod+f[i]-f[j]*C(i-1,j-1)%mod*mi[(i-j)*(i-j-1)/2]%mod)%mod;
    }
    printf("%lld",f[n]);
    return 0;
}
